group = 'com.pvpbot'
version = '1.0.0'

java {
    sourceCompatibility = JavaVersion.VERSION_25
    targetCompatibility = JavaVersion.VERSION_25
}

repositories {
    mavenCentral()
    maven { url 'https://repo.papermc.io/repository/maven-public/' }
    maven { url 'https://repo.comphenix.net/content/repositories/public/' }
    ivy {
        url 'https://ci.citizensnpcs.co/job/Citizens2/lastSuccessfulBuild/artifact/'
        patternLayout {
            artifact 'dist/target/[artifact]-[revision].[ext]'
        }
    }
}

